INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 155, "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ", "A", 0, 16, "トゥインクルウィッシュ", 100101, 2, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (47, 4, 158, "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ", "O", 0, 17, "トゥインクルウィッシュ", 100201, 2, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 1, 163, "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ", "B", 0, 18, "トゥインクルウィッシュ", 100301, 2, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (27, 8, 128, "いたずら、探検", 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "探検好きのイタズラっ子", "諸星すみれ", "ミソギ", "O", 0, 9, "リトルリリカル", 100401, 5, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 146, "ヒーローごっこ", 25, "？？？", "ヒーローに憧れる騎士見習いの少女", "下田麻美", "マツリ", "O", 0, 12, "王宮騎士団（NIGHTMARE）", 100501, 8, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 11, 150, "サックス", 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "甘え上手なみんなの人気者", "浅倉杏美", "アカリ", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 100601, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (32, 1, 130, "プリンを食べること", 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", "雨宮天", "ミヤコ", "B", 0, 14, "悪魔偽王国軍（ディアボロス）", 100701, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 10, 150, "鏡で自分を見ること", 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ボクは誰よりも美しい", "大空直美", "ユキ", "AB", 0, 14, "ヴァイスフリューゲル　ランドソル支部", 100801, 15, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 7, 159, "小説執筆", 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ", "A", 0, 17, "トワイライトキャラバン", 100901, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 9, 155, "空想、ぬいぐるみ集め", 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホマホ王国のプリンセス", "内田真礼", "マホ", "O", 0, 16, "自警団（カォン）", 101001, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 156, "お裁縫", 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ", "A", 0, 15, "ラビリンス", 101101, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 12, 156, "妹と遊ぶこと、二度寝、昼寝、早寝", 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ", "A", 0, 17, "フォレスティエ", 101201, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 8, 166, "読書、魔法", 21, "", "オタク全開な魔法少女", "佳村はるか", "ナナカ", "O", 0, 18, "トワイライトキャラバン", 101301, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (41, 11, 152, "読書、推理", 3, "test", "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ", "AB", 0, 15, "自警団（カォン）", 101401, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 9, 165, "絵本作り", 5, "test", "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "ミサト", "O", 0, 21, "フォレスティエ", 101501, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 4, 167, "ファッション", 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ", "O", 0, 17, "ルーセント学院", 101601, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 7, 158, "踊り、空手", 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "カオリ", "A", 0, 17, "自警団（カォン）", 101701, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (52, 8, 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "多くの男性を魅了する無垢な女教師", "伊藤静", "イオ", "B", 0, 23, "ルーセント学院", 101801, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (21, 4, 117, "かわいいもの集め", 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ", "O", 0, 10, "リトルリリカル", 102001, 5, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 6, 150, "観劇、おままごと", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ", "B", 0, 12, "サレンディア救護院", 102101, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 150, "ゲーム全般", 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "人見知りであまのじゃくな女の子", "原紗友里", "ヨリ", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 102201, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (38, 5, 148, "屋内でできる遊び", 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", "芹澤優", "アヤネ", "B", 0, 14, "サレンディア救護院", 102301, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 12, 154, "ご奉仕", 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ", "O", 0, 15, "サレンディア救護院", 102501, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 1, 144, "あんパン", 1, "test", "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "リン", "B", 0, 17, "牧場（エリザベスパーク）", 102601, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 7, 154, "実験、裁縫、料理", 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ", "B", 0, 16, "トワイライトキャラバン", 102701, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 10, 156, "経営、お茶会", 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン", "A", 0, 17, "サレンディア救護院", 102801, 9, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 1, 157, "舞台鑑賞、ダンス", 24, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "歌って踊れる大人気アイドル", "日笠陽子", "ノゾミ", "B", 0, 17, "カルミナ", 102901, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (51, 8, 163, "忍法開発", 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 103001, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 12, 157, "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "大坪由佳", "シノブ", "AB", 0, 18, "悪魔偽王国軍（ディアボロス）", 103101, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 3, 157, "慈善事業", 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "アキノ", "AB", 0, 18, "メルクリウス財団", 103201, 12, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 3, 142, "漫才", 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル", "B", 0, 20, "牧場（エリザベスパーク）", 103301, 11, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 3, 164, "ウインドーショッピング", 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", "今井麻美", "ユカリ", "A", 0, 22, "メルクリウス財団", 103401, 12, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (21, 2, 118, "お勉強", 2, "test", "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "キョウカ", "A", 0, 8, "リトルリリカル", 103601, 5, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 8, 149, "剣術、年長者をからかう", 11, "test", "義理堅くてからかい好きな剣術少女", "茅原実里", "トモ", "A", 0, 13, "王宮騎士団（NIGHTMARE）", 103701, 8, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 153, "読書、お散歩", 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "読書が趣味の病弱少女", "小清水亜美", "シオリ", "A", 0, 14, "牧場（エリザベスパーク）", 103801, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 6, 158, "友達作りのイメトレ", 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ", "AB", 0, 13, "フォレスティエ", 104001, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 6, 163, "各種楽器", 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ", "O", 0, 17, "カルミナ", 104201, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 8, 168, "お菓子作り", 9, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "男勝りで情に厚いワイルド娘", "小松未可子", "マコト", "O", 0, 17, "自警団（カォン）", 104301, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 5, 172, "世界征服", 5, "test", "かつては夜を支配した最強の吸血鬼", "丹下桜", "イリヤ", "A", 0, "??", "悪魔偽王国軍（ディアボロス）", 104401, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 157, "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ", "AB", 0, 18, "ヴァイスフリューゲル　ランドソル支部", 104501, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 3, 158, "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ", "AB", 0, 19, "メルクリウス財団", 104601, 12, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 10, 171, "格闘技、湯浴み", 25, "？？？", "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン", "A", 0, 25, "王宮騎士団（NIGHTMARE）", 104701, 8, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 163, "傭兵などのアルバイト", 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ", "O", 0, 20, "メルクリウス財団", 104801, 12, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 10, 168, "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル", "O", 0, 18, "ラビリンス", 104901, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (22, 1, 120, "ファッション誌鑑賞、コスメ集め", 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ", "A", 0, 11, "ルーセント学院", 105001, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 3, 166, "研究、実験", 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", "三石琴乃", "ミツキ", "A", 0, 27, "トワイライトキャラバン", 105101, 13, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (100, 3, 150, "毛繕い、お喋り", 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "乙女チックなもふもふアニマル", "徳井青空", "リマ", "A", 0, 17, "牧場（エリザベスパーク）", 105201, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (33, 7, 140, "お菓子屋通い", 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ", "A", 0, 17, "ヴァイスフリューゲル　ランドソル支部", 105301, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 9, 153, "裁縫", 7, "test", "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ", "AB", 0, 14, "カルミナ", 105401, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 4, 155, "観察", 7, "test", "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 105501, 15, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 7, 167, "釣り", 11, "test", "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "ルカ", "B", 0, 25, "トワイライトキャラバン", 105601, 13, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 3, 156, "冒険、おしゃべり", 10, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "空への冒険を夢見る騎空士の少女", "金元寿子", "ジータ", "O", 0, 17, "？？？", 105701, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 3, 156, "食べ歩き、料理", 31, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "いつも元気な腹ペコ少女", "M・A・O", "ペコリーヌ", "O", 0, 17, "美食殿", 105801, 1, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 5, 140, "瞑想、動植物の飼育", 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", "伊藤美来", "コッコロ", "B", 0, 11, "美食殿", 105901, 1, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (39, 9, 152, "猫と遊ぶ", 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル", "A", 0, 14, "美食殿", 106001, 1, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 8, 148, "冒険、思い出話", 11, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "さまよえる謎の少女", "潘めぐみ", "ムイミ", "O", 0, 16, "？？？", 106101, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 6, 155, "キレイな葉っぱを集めること", 17, "", "森番を目指すエルフの少女", "優木かな", "アリサ", "O", 0, 15, "？？？", 106301, "", "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 12, 147, "読書、ストレッチ", 14, "", "記憶喪失のドラゴン娘", "近藤玲奈", "シェフィ", "B", 0, 14, "美食殿", 106401, 1, "ドラゴン族");
