INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 9, 145, "ゲーム", 29, "", "口が達者なヘタレドラゴン", "藤田茜", "イノリ", "AB", 0, 13, "ドラゴンズネスト", 106601, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 4, 168, "絵画、読書", 17, "", "妖しい微笑で全てを見透かす臥竜の頭領", "大西沙織", "ホマレ", "O", 0, 25, "ドラゴンズネスト", 106701, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 7, 160, "人間観察", 25, "", "秘密結社ラビリンスの『迷宮女王』", "沢城みゆき", "ラビリスタ", "AB", 0, 25, "ラビリンス", 106801, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 7, 166, "占い、支配", 1, "", "謎に包まれたランドソルの主", "蒼井翔太", "カイザーインサイト", "AB", 0, 29, "？？？", 106901, "", "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 3, 149, "物真似、芸術鑑賞", 24, "", "研究所に隠れ住む物静かなお姉さん", "井口裕香", "ネネカ", "O", 0, 24, "？？？", 107001, "", "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 2, 165, "強敵との闘争", 7, "", "傍若無人な王宮騎士団副団長", "たかはし智秋", "クリスティーナ", "O", 0, 27, "王宮騎士団（NIGHTMARE）", 107101, 8, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 3, 156, "食べ歩き、料理", 31, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "いつも元気な腹ペコ少女", "M・A・O", "ペコリーヌ（サマー）", "O", 0, 17, "美食殿", 107501, 1, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 5, 140, "瞑想、動植物の飼育", 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（サマー）", "B", 0, 11, "美食殿", 107601, 1, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 12, 154, "ご奉仕", 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ（サマー）", "O", 0, 15, "サレンディア救護院", 107701, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (39, 9, 152, "猫と遊ぶ", 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（サマー）", "A", 0, 14, "美食殿", 107801, 1, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 3, 158, "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（サマー）", "AB", 0, 19, "メルクリウス財団", 107901, 12, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 163, "傭兵などのアルバイト", 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ（サマー）", "O", 0, 20, "メルクリウス財団", 108001, 12, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 12, 157, "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "大坪由佳", "シノブ（ハロウィン）", "AB", 0, 18, "悪魔偽王国軍（ディアボロス）", 108101, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (32, 1, 130, "プリンを食べること", 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", "雨宮天", "ミヤコ（ハロウィン）", "B", 0, 14, "悪魔偽王国軍（ディアボロス）", 108201, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (22, 1, 120, "ファッション誌鑑賞、コスメ集め", 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ（ハロウィン）", "A", 0, 11, "ルーセント学院", 108301, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 6, 163, "各種楽器", 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ（クリスマス）", "O", 0, 17, "カルミナ", 108401, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 6, 150, "観劇、おままごと", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ（クリスマス）", "B", 0, 12, "サレンディア救護院", 108501, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (38, 5, 148, "屋内でできる遊び", 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", "芹澤優", "アヤネ（クリスマス）", "B", 0, 14, "サレンディア救護院", 108601, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 155, "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（ニューイヤー）", "A", 0, 16, "トゥインクルウィッシュ", 108701, 2, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (47, 4, 158, "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（ニューイヤー）", "O", 0, 17, "トゥインクルウィッシュ", 108801, 2, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 1, 163, "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（ニューイヤー）", "B", 0, 18, "トゥインクルウィッシュ", 108901, 2, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 7, 154, "実験、裁縫、料理", 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ（バレンタイン）", "B", 0, 16, "トワイライトキャラバン", 109001, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 10, 168, "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（バレンタイン）", "O", 0, 18, "ラビリンス", 109101, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 12, 156, "読書", 1, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "英霊と契約を結んだマナリアの天才王女", "日笠陽子", "アン", "AB", 0, 17, "？？？", 109201, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 2, 144, "食べること、眠ること", 4, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "マナリア魔法学院の新入生", "こやまきみこ", "ルゥ", "O", 0, 16, "？？？", 109301, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (67, 11, 167, "ピアノ", 3, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "人を超越した力を有す心優しい竜姫", "福原綾香", "グレア", "B", 0, 17, "？？？", 109401, "", "半人半竜");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 157, "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（オーエド）", "AB", 0, 18, "ヴァイスフリューゲル　ランドソル支部", 109501, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (51, 8, 163, "忍法開発", 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン（オーエド）", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 109601, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 2, 154, "演劇鑑賞、詩文", 2, "", "鬼がかりの万能妹メイド", "水瀬いのり", "レム", "?", 0, 17, "？？？", 109701, "", "鬼族");
