INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (21, 4, 117, "かわいいもの集め", 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ（ハロウィン）", "O", 0, 10, "リトルリリカル", 111301, 5, "獣人族");
