INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 5, 172, "世界征服", 5, "", "かつては夜を支配した最強の吸血鬼", "丹下桜", "イリヤ（クリスマス）", "A", 0, "??", "悪魔偽王国軍（ディアボロス）", 111701, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 3, 156, "食べ歩き、料理", 31, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "いつも元気な腹ペコ少女", "M・A・O", "ぺコリーヌ（ニューイヤー）", "O", 0, 17, "美食殿", 111801, 1, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 5, 140, "瞑想、動植物の飼育", 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（ニューイヤー）", "B", 0, 11, "美食殿", 111901, 1, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (39, 9, 152, "猫と遊ぶ", 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（ニューイヤー）", "A", 0, 14, "美食殿", 112001, 1, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 12, 154, "ご奉仕", 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ（ニューイヤー）", "O", 0, 15, "サレンディア救護院", 112101, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (41, 11, 152, "読書、推理", 3, "", "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ（マジカル）", "AB", 0, 15, "自警団（カォン）", 112201, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 153, "読書、お散歩", 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "読書が趣味の病弱少女", "小清水亜美", "シオリ（マジカル）", "A", 0, 14, "牧場（エリザベスパーク）", 112301, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 4, 159, "友達と長話", 24, "", "弾ける笑顔！　アイドルを夢見る女の子", "大橋彩香", "ウヅキ（デレマス）", "O", 0, 17, "ニュージェネレーションズ", 112401, 100, "ヒューマン");
