INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 1, 144, "あんパン", 1, "", "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "リン（レンジャー）", "B", 0, 17, "牧場（エリザベスパーク）", 112701, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 3, 142, "漫才", 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル（レンジャー）", "B", 0, 20, "牧場（エリザベスパーク）", 112801, 11, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 156, "お裁縫", 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ（ワンダー）", "A", 0, 15, "ラビリンス", 112901, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 4, 155, "観察", 7, "", "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ（ワンダー）", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 113001, 15, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 7, 167, "釣り", 11, "", "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "ルカ（サマー）", "B", 0, 25, "トワイライトキャラバン", 113101, 13, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 7, 159, "小説執筆", 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ（サマー）", "A", 0, 17, "トワイライトキャラバン", 113201, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 8, 166, "読書、魔法", 21, "", "オタク全開な魔法少女", "佳村はるか", "ナナカ（サマー）", "O", 0, 18, "トワイライトキャラバン", 113301, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 12, 156, "妹と遊ぶこと、二度寝、昼寝、早寝", 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ（サマー）", "A", 0, 17, "フォレスティエ", 113401, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 9, 165, "絵本作り", 5, "", "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "ミサト（サマー）", "O", 0, 21, "フォレスティエ", 113501, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 10, 171, "格闘技、湯浴み", 25, "", "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン（サマー）", "A", 0, 25, "王宮騎士団（NIGHTMARE）", 113601, 8, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 11, 150, "サックス", 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "甘え上手なみんなの人気者", "浅倉杏美", "アカリ（エンジェル）", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 113701, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 150, "ゲーム全般", 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "人見知りであまのじゃくな女の子", "原紗友里", "ヨリ（エンジェル）", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 113801, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 9, 153, "裁縫", 7, "", "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ（ハロウィン）", "AB", 0, 14, "カルミナ", 113901, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 1, 163, "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（ハロウィン）", "B", 0, 18, "トゥインクルウィッシュ", 114001, 2, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 146, "ヒーローごっこ", 25, "", "ヒーローに憧れる騎士見習いの少女", "下田麻美", "マツリ（ハロウィン）", "O", 0, 12, "王宮騎士団（NIGHTMARE）", 114101, 8, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (33, 7, 140, "お菓子屋通い", 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ（マジカル）", "A", 0, 17, "ヴァイスフリューゲル　ランドソル支部", 114201, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 8, 149, "剣術、年長者をからかう", 11, "", "義理堅くてからかい好きな剣術少女", "茅原実里", "トモ（マジカル）", "A", 0, 13, "王宮騎士団（NIGHTMARE）", 114301, 8, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 3, 157, "慈善事業", 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "アキノ（クリスマス）", "AB", 0, 18, "メルクリウス財団", 114401, 12, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 10, 156, "経営、お茶会", 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（クリスマス）", "A", 0, 17, "サレンディア救護院", 114501, 9, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 3, 164, "ウインドーショッピング", 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", "今井麻美", "ユカリ（クリスマス）", "A", 0, 22, "メルクリウス財団", 114601, 12, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 8, 148, "冒険、思い出話", 11, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "さまよえる謎の少女", "潘めぐみ", "ムイミ（ニューイヤー）", "O", 0, 16, "？？？", 114701, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 3, 149, "物真似、芸術鑑賞", 24, "", "研究所に隠れ住む物静かなお姉さん", "井口裕香", "ネネカ（ニューイヤー）", "O", 0, 24, "？？？", 115001, "", "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 5, 140, "瞑想、動植物の飼育", 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（儀装束）", "B", 0, 11, "美食殿", 115501, 1, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (47, 4, 158, "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（儀装束）", "O", 0, 17, "トゥインクルウィッシュ", 115601, 2, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (41, 11, 152, "読書、推理", 3, "", "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ（サマー）", "AB", 0, 15, "自警団（カォン）", 115701, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (100, 3, 150, "毛繕い、お喋り", 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "乙女チックなもふもふアニマル", "徳井青空", "リマ（シンデレラ）", "A", 0, 17, "牧場（エリザベスパーク）", 115801, 11, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 8, 168, "お菓子作り", 9, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "男勝りで情に厚いワイルド娘", "小松未可子", "マコト（シンデレラ）", "O", 0, 17, "自警団（カォン）", 115901, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 9, 155, "空想、ぬいぐるみ集め", 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホマホ王国のプリンセス", "内田真礼", "マホ（シンデレラ）", "O", 0, 16, "自警団（カォン）", 116001, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 8, 154, "ダーツ", 7, "", "ダウンタウン育ちのダウナー系エルフ", "種﨑敦美", "クロエ（聖学祭）", "O", 0, 17, "聖テレサ女学院（なかよし部）", 116201, 16, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 9, 156, "ダンス、カラオケ", 15, "", "自由奔放ナチュラル無礼な現代っ子", "佐倉綾音", "チエル（聖学祭）", "O", 0, 16, "聖テレサ女学院（なかよし部）", 116301, 16, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (36, 2, 142, "読書", 28, "", "書庫に眠れる小さな賢人", "小原好美", "ユニ（聖学祭）", "O", 0, 18, "聖テレサ女学院（なかよし部）", 116401, 16, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 9, 145, "ゲーム", 29, "", "口が達者なヘタレドラゴン", "藤田茜", "イノリ（タイムトラベル）", "AB", 0, 13, "ドラゴンズネスト", 116501, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 6, 156, "格闘技", 25, "", "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "カヤ（タイムトラベル）", "B", 0, 16, "ドラゴンズネスト", 116601, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 6, 158, "友達作りのイメトレ", 6, "", "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ（作業服）", "AB", 0, 13, "フォレスティエ", 116701, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 3, 158, "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（作業服）", "AB", 0, 19, "メルクリウス財団", 116801, 12, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 163, "傭兵などのアルバイト", 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ（作業服）", "O", 0, 20, "メルクリウス財団", 116901, 12, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 7, 154, "実験、裁縫、料理", 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ（サマー）", "B", 0, 16, "トワイライトキャラバン", 117001, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 10, 168, "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（サマー）", "O", 0, 18, "ラビリンス", 117101, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 1, 157, "舞台鑑賞、ダンス", 24, "", "歌って踊れる大人気アイドル", "日笠陽子", "ノゾミ（サマー）", "B", 0, 17, "カルミナ", 117201, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 6, 163, "各種楽器", 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ（サマー）", "O", 0, 17, "カルミナ", 117301, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 9, 153, "裁縫", 7, "", "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ（サマー）", "AB", 0, 14, "カルミナ", 117401, 4, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 3, 166, "研究、実験", 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", "三石琴乃", "ミツキ（オーエド）", "A", 0, 27, "トワイライトキャラバン", 117501, 13, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 10, 150, "鏡で自分を見ること", 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ボクは誰よりも美しい", "大空直美", "ユキ（オーエド）", "AB", 0, 14, "ヴァイスフリューゲル　ランドソル支部", 117601, 15, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 7, 158, "踊り、空手", 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "カオリ（ハロウィン）", "A", 0, 17, "自警団（カォン）", 117701, 10, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (51, 8, 163, "忍法開発", 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン（ハロウィン）", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 117801, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 4, 167, "ファッション", 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ（ハロウィン）", "O", 0, 17, "ルーセント学院", 117901, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (57, 9, 160, "お金を数えること、悪だくみ", 19, "", "忠義に目覚めた女商人", "Lynn", "クレジッタ", "A", 0, 26, "リッチモンド商工会", 118001, 18, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 12, 165, "歌、読書、詩を書くこと", 28, "", "静寂を求め歌う陰気少女", "原田彩楓", "ランファ", "O", 0, 20, "レイジ・レギオン", 118101, 19, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 7, 159, "特に無し", 2, "", "明朗快活、なれど破滅に流るる溌溂少女", "鬼頭明里", "ミソラ", "A", 0, 16, "レイジ・レギオン", 118201, 19, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 9, 152, "書類仕事、散歩、ボードゲーム", 12, "", "【ギルド管理協会】職員の親切なお姉さん", "洲崎綾", "カリン", "A", 0, 24, "？？？", 118501, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", "?", "???", "悪戯をすること", "?", "", "幻霧に戯れる悪戯好きなガイド妖精", "相坂優歌", "ネビア", "?", 0, "??", "？？？", 118601, "", "？？？");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (52, 8, 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "多くの男性を魅了する無垢な女教師", "伊藤静", "イオ（ノワール）", "B", 0, 23, "ルーセント学院", 119001, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 157, "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（ノワール）", "AB", 0, 18, "ヴァイスフリューゲル　ランドソル支部", 119101, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 3, 142, "漫才", 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル（クリスマス）", "B", 0, 20, "牧場（エリザベスパーク）", 119201, 11, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 156, "お裁縫", 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ（クリスマス）", "A", 0, 15, "ラビリンス", 119301, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (32, 1, 130, "プリンを食べること", 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", "雨宮天", "ミヤコ（クリスマス）", "B", 0, 14, "悪魔偽王国軍（ディアボロス）", 119901, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 10, 168, "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（ノワール）", "O", 0, 18, "ラビリンス", 120001, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 12, 147, "読書、ストレッチ", 14, "", "記憶喪失のドラゴン娘", "近藤玲奈", "シェフィ（ニューイヤー）", "B", 0, 14, "美食殿", 120701, 1, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (54, 7, 167, "釣り", 11, "", "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "ルカ（ニューイヤー）", "B", 0, 25, "トワイライトキャラバン", 120801, 13, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 5, 172, "世界征服", 5, "", "かつては夜を支配した最強の吸血鬼", "丹下桜", "イリヤ（ニューイヤー）", "A", 0, "??", "悪魔偽王国軍（ディアボロス）", 120901, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 3, 156, "食べ歩き、料理", 31, "", "いつも元気な腹ペコ少女", "M・A・O", "ぺコリーヌ（オーバーロード）", "O", 0, 17, "美食殿", 121001, 1, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (39, 9, 152, "猫と遊ぶ", 2, "", "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（オーバーロード）", "A", 0, 14, "美食殿", 121101, 1, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("??", 7, 160, "人間観察", 25, "", "秘密結社ラビリンスの『迷宮女王』", "沢城みゆき", "ラビリスタ（オーバーロード）", "AB", 0, 25, "ラビリンス", 121201, 3, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 6, 150, "観劇、おままごと", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ（ステージ）", "B", 0, 12, "サレンディア救護院", 121301, 9, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (22, 1, 120, "ファッション誌鑑賞、コスメ集め", 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ（ステージ）", "A", 0, 11, "ルーセント学院", 121401, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 4, 155, "観察", 7, "", "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ（怪盗）", "O", 0, 16, "ヴァイスフリューゲル　ランドソル支部", 121501, 15, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 9, 145, "ゲーム", 29, "", "口が達者なヘタレドラゴン", "藤田茜", "イノリ（怪盗）", "AB", 0, 13, "ドラゴンズネスト", 121601, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (45, 7, 159, "小説執筆", 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ（パイレーツ）", "A", 0, 17, "トワイライトキャラバン", 121901, 13, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 12, 157, "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "大坪由佳", "シノブ（パイレーツ）", "AB", 0, 18, "悪魔偽王国軍（ディアボロス）", 122001, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 6, 158, "友達作りのイメトレ", 6, "", "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ（キャンプ）", "AB", 0, 13, "フォレスティエ", 122101, 6, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 3, 164, "ウインドーショッピング", 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", "今井麻美", "ユカリ（キャンプ）", "A", 0, 22, "メルクリウス財団", 122201, 12, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (41, 12, 149, "お散歩、お料理", 6, "", "けんぞくのご主人様", "釘宮理恵", "ヴァンピィ", "AB", 0, "??", "？？？", 122301, "", "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 155, "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（サマー）", "A", 0, 16, "トゥインクルウィッシュ", 122401, 2, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 1, 163, "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（サマー）", "B", 0, 18, "トゥインクルウィッシュ", 122501, 2, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (47, 4, 158, "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（サマー）", "O", 0, 17, "トゥインクルウィッシュ", 122601, 2, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (21, 2, 118, "お勉強", 2, "", "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "キョウカ（サマー）", "A", 0, 8, "リトルリリカル", 122701, 5, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (27, 8, 128, "いたずら、探検", 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "探検好きのイタズラっ子", "諸星すみれ", "ミソギ（サマー）", "O", 0, 9, "リトルリリカル", 122801, 5, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (21, 4, 117, "かわいいもの集め", 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ（サマー）", "O", 0, 10, "リトルリリカル", 122901, 5, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", "?", 150, "？？？", "?", "", "新たな姿で騎士の冒険を支え続ける妖精", "相坂優歌", "アメス", "?", 0, "??", "？？？", 123001, "", "？？？");
