INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (38, 5, 148, "屋内でできる遊び", 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", "芹澤優", "アヤネ（エクスプローラー）", "B", 0, 14, "サレンディア救護院", 123201, 9, "ヒューマン");
