INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 11, 150, "サックス", 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "甘え上手なみんなの人気者", "浅倉杏美", "アカリ（クリスマス）", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 124001, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 150, "ゲーム全般", 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "人見知りであまのじゃくな女の子", "原紗友里", "ヨリ（クリスマス）", "O", 0, 13, "悪魔偽王国軍（ディアボロス）", 124101, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (50, 10, 171, "格闘技、湯浴み", 25, "", "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン（クリスマス）", "A", 0, 25, "王宮騎士団（NIGHTMARE）", 124201, 8, "ヒューマン");
