INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 3, 166, "研究、実験", 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", "三石琴乃", "ミツキ（ニューイヤー）", "A", 0, 27, "トワイライトキャラバン", 124701, 13, "ヒューマン");
