INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES ("???", 6, 156, "格闘技", 25, "", "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "カヤ（リベレイター）", "B", 0, 16, "ドラゴンズネスト", 124901, 17, "ドラゴン族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 8, 148, "冒険、思い出話", 11, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "さまよえる謎の少女", "潘めぐみ", "ムイミ（リベレイター）", "O", 0, 16, "？？？", 125001, "", "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 3, 158, "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（カフェ）", "AB", 0, 19, "メルクリウス財団", 125101, 12, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (33, 7, 140, "お菓子屋通い", 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ（カフェ）", "A", 0, 17, "ヴァイスフリューゲル　ランドソル支部", 125201, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (35, 5, 140, "瞑想、動植物の飼育", 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（レンジャー）", "B", 0, 11, "美食殿", 125301, 1, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (40, 11, 153, "読書、お散歩", 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "読書が趣味の病弱少女", "小清水亜美", "シオリ（レンジャー）", "A", 0, 14, "牧場（エリザベスパーク）", 125401, 11, "獣人族");
