INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (55, 3, 164, "ウインドーショッピング", 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", "今井麻美", "ユカリ（サマー）", "A", 0, 22, "メルクリウス財団", 126801, 12, "エルフ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (53, 12, 165, "歌、読書、詩を書くこと", 28, "", "静寂を求め歌う陰気少女", "原田彩楓", "ランファ（サマー）", "O", 0, 20, "レイジ・レギオン", 126901, 19, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (49, 11, 157, "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（サマー）", "AB", 0, 18, "ヴァイスフリューゲル　ランドソル支部", 127001, 15, "ヒューマン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (42, 12, 157, "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "大坪由佳", "シノブ（サマー）", "AB", 0, 18, "悪魔偽王国軍（ディアボロス）", 127101, 7, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (39, 9, 152, "猫と遊ぶ", 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（編入生）", "A", 0, 14, "美食殿", 127201, 1, "獣人族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (48, 4, 167, "ファッション", 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ（編入生）", "O", 0, 17, "ルーセント学院", 127301, 14, "魔族");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (43, 10, 156, "経営、お茶会", 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（サラサリア）", "A", 0, 17, "サレンディア救護院", 127501, 9, "エルフ");
