INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (46, 12, 156, "妹と遊ぶこと、二度寝、昼寝、早寝", 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ（ニューイヤー）", "A", 0, 17, "フォレスティエ", 128401, 6, "エルフ");
