INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (44, 8, 155, "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（アストラル）", "A", 0, 16, "トゥインクルウィッシュ", 128701, 2, "獣人族");
