INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (47, 4, 158, "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（アストラル）", "O", 0, 17, "トゥインクルウィッシュ", 128901, 2, "ヒューマン");
